fn test_complex_struct() {
    println!("--- Testing ComplexStruct ---");

    let original = ComplexStruct {
        user_id: 999888777,
        username: "power_user".to_string(),
        emails: vec![
            "user@example.com".to_string(),
            "backup@example.com".to_string(),
        ],
        settings: NestedStruct {
